using UnityEngine;

// Health component — handles health and damage
public class HealthComponent : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth;

    public event System.Action OnDeath;
    public event System.Action<int> OnDamageTaken;

    void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int damage)
    {
        currentHealth -= damage;
        if (currentHealth < 0) currentHealth = 0;

        OnDamageTaken?.Invoke(damage);

        if (currentHealth <= 0)
        {
            OnDeath?.Invoke();
        }
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth) currentHealth = maxHealth;
    }

    public bool IsAlive => currentHealth > 0;
    public float HealthPercent => (float)currentHealth / maxHealth;
}

// Movement component — handles player movement
public class MovementComponent : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float jumpForce = 10f;
    private Rigidbody2D rb;
    private bool isGrounded;

    void Start()
    {
        rb = GetComponent<Rigidbody2D>();
    }

    void Update()
    {
        float horizontal = Input.GetAxis("Horizontal");
        Vector2 velocity = rb.velocity;
        velocity.x = horizontal * moveSpeed;
        rb.velocity = velocity;

        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
        }
    }

    void OnCollisionEnter2D(Collision2D collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            isGrounded = true;
        }
    }
}

// Attack component — handles attacking
public class AttackComponent : MonoBehaviour
{
    public int attackPower = 10;
    public float attackRange = 2f;
    public float attackCooldown = 0.5f;
    private float lastAttackTime;

    void Update()
    {
        if (Input.GetButtonDown("Fire1") && Time.time > lastAttackTime + attackCooldown)
        {
            PerformAttack();
        }
    }

    void PerformAttack()
    {
        lastAttackTime = Time.time;

        // Raycast or overlap check for enemies
        Collider2D[] hits = Physics2D.OverlapCircleAll(transform.position, attackRange);
        foreach (Collider2D hit in hits)
        {
            HealthComponent health = hit.GetComponent<HealthComponent>();
            if (health != null && hit.gameObject != gameObject)
            {
                health.TakeDamage(attackPower);
                Debug.Log("Attacked: " + hit.gameObject.name);
            }
        }

        Debug.Log("Attack performed!");
    }
}

// Player controller — composes all components together
public class PlayerController : MonoBehaviour
{
    private HealthComponent health;
    private MovementComponent movement;
    private AttackComponent attack;

    void Start()
    {
        health = GetComponent<HealthComponent>();
        movement = GetComponent<MovementComponent>();
        attack = GetComponent<AttackComponent>();

        if (health == null)
        {
            Debug.LogError("Missing HealthComponent!");
        }

        // Subscribe to health events
        health.OnDeath += OnPlayerDeath;
        health.OnDamageTaken += OnPlayerDamaged;
    }

    void OnPlayerDeath()
    {
        Debug.Log("Player has died!");
        // Disable components
        enabled = false;
    }

    void OnPlayerDamaged(int damage)
    {
        Debug.Log("Player took " + damage + " damage! Health: " + health.currentHealth);
    }
}

public class ComponentPatternExample : MonoBehaviour
{
    void Start()
    {
        // The component pattern is already demonstrated above
        // In a real project, you'd attach these components to a GameObject
        Debug.Log("Component Pattern Example — see the classes above");
    }
}

